/* ---------------------------------------------
   META TAGS — injected into document head for OG/link preview
--------------------------------------------- */
function MetaTags() {
  useEffect(() => {
    // OG image for link previews (social media, iMessage, Slack etc.)
    const metas = [
      { property: "og:title", content: "Simge — Motion Designer & Creative Visual Designer" },
      { property: "og:description", content: "Bringing stories to life through purposeful design and motion." },
      { property: "og:image", content: OG_IMAGE_B64 },
      { property: "og:type", content: "website" },
      { name: "twitter:card", content: "summary_large_image" },
      { name: "twitter:image", content: OG_IMAGE_B64 },
    ];
    metas.forEach(({ property, name, content }) => {
      const el = document.createElement("meta");
      if (property) el.setAttribute("property", property);
      if (name) el.setAttribute("name", name);
      el.setAttribute("content", content);
      document.head.appendChild(el);
    });
  }, []);
  return null;
}

/* ---------------------------------------------
   SPLASH SCREEN — plays the logo animation on first load
--------------------------------------------- */
function SplashScreen({ onDone }) {
  const containerRef = useRef(null);
  const [visible, setVisible] = useState(true);

  useEffect(() => {
    if (!containerRef.current) return;
    let anim;

    function init() {
      if (!window.lottie || !containerRef.current) return;
      anim = window.lottie.loadAnimation({
        container: containerRef.current,
        renderer: "svg",
        loop: false,
        autoplay: true,
        animationData: LOTTIE_SPLASH,
      });
      anim.addEventListener("complete", () => {
        // Short hold after animation ends, then fade out
        setTimeout(() => {
          setVisible(false);
          setTimeout(onDone, 600); // wait for fade-out transition
        }, 300);
      });
    }

    if (window.lottie) {
      init();
    } else {
      const script = document.createElement("script");
      script.src = "https://cdnjs.cloudflare.com/ajax/libs/lottie-web/5.12.2/lottie.min.js";
      script.onload = init;
      document.body.appendChild(script);
    }

    return () => { if (anim) anim.destroy(); };
  }, []);

  return (
    <motion.div
      initial={{ opacity: 1 }}
      animate={{ opacity: visible ? 1 : 0 }}
      transition={{ duration: 0.5, ease: "easeOut" }}
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 9999,
        backgroundColor: COLORS.bg,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <div
        ref={containerRef}
        style={{ width: "260px", height: "260px" }}
      />
    </motion.div>
  );
}

