/* ---------------------------------------------
   SWITCH BUTTON — chill / work pill toggle
   Recreates the provided pill illustration with a
   sliding colored dot and crossfading label
--------------------------------------------- */
function SwitchButton({ mode, onToggle }) {
  const isWork = mode === "work";
  const dotSize = 44;
  const edgePad = 7;
  const pillWidth = 152; // inner content-box width
  const borderWidth = 2.5;
  const pillHeight = dotSize + edgePad * 2; // inner content-box height
  const outerWidth = pillWidth + borderWidth * 2; // total rendered width incl. border
  const outerHeight = pillHeight + borderWidth * 2; // total rendered height incl. border

  return (
    <button
      type="button"
      onClick={onToggle}
      aria-label={isWork ? "Switch to chill mode" : "Switch to work mode"}
      aria-pressed={isWork}
      className="relative mx-auto block rounded-full"
      style={{
        width: `${outerWidth}px`,
        height: `${outerHeight}px`,
        border: `2.5px solid ${COLORS.ink}`,
        backgroundColor: "transparent",
        boxSizing: "border-box",
        padding: 0,
        margin: "0 auto",
        lineHeight: 0,
        transform: "scale(var(--pill-scale, 1))",
        transformOrigin: "top center",
      }}
    >
      {/* Sliding dot — vertically centered via flex, not top offset */}
      <motion.div
        className="absolute rounded-full flex items-center justify-center"
        style={{ width: `${dotSize}px`, height: `${dotSize}px`, top: `${(pillHeight - dotSize) / 2}px` }}
        animate={{
          left: isWork ? `${pillWidth - edgePad - dotSize}px` : `${edgePad}px`,
          backgroundColor: isWork ? COLORS.ink : COLORS.accent,
        }}
        transition={{ type: "spring", stiffness: 260, damping: 22 }}
      />

      {/* Label — single text that crossfades, vertically centered via flex */}
      <div className="absolute inset-0 flex items-center">
        <AnimatePresence mode="wait" initial={false}>
          {isWork ? (
            <motion.span
              key="work-label"
              className="absolute font-display font-bold text-xl leading-none flex items-center"
              style={{ color: COLORS.ink, left: `${edgePad + 8}px`, top: 0, bottom: 0 }}
              initial={{ opacity: 0, x: -6 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -6 }}
              transition={{ duration: 0.2, ease: "easeOut" }}
            >
              Work
            </motion.span>
          ) : (
            <motion.span
              key="chill-label"
              className="absolute font-display font-bold text-xl leading-none flex items-center"
              style={{ color: COLORS.ink, right: `${edgePad + 8}px`, top: 0, bottom: 0 }}
              initial={{ opacity: 0, x: 6 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 6 }}
              transition={{ duration: 0.2, ease: "easeOut" }}
            >
              Chill
            </motion.span>
          )}
        </AnimatePresence>
      </div>
    </button>
  );
}

/* ---------------------------------------------
   HEADER
--------------------------------------------- */
function Header() {
  const [open, setOpen] = useState(false);
  const links = [
    { label: "About", href: "#about" },
    { label: "Services", href: "#services" },
    { label: "Work", href: "#portfolio" },
    { label: "Contact", href: "#contact" },
  ];

  function scrollToSection(e, href) {
    e.preventDefault();
    const id = href.replace("#", "");
    const el = document.getElementById(id);
    if (el) {
      el.scrollIntoView({ behavior: "smooth", block: "start" });
    }
    setOpen(false);
  }

  return (
    <header
      className="sticky top-0 z-50 w-full backdrop-blur-md"
      style={{ backgroundColor: `${COLORS.bg}E6` }}
    >
      <div className="max-w-6xl mx-auto px-6 md:px-10 h-20 flex items-center justify-between">
        <a
          href="#top"
          onClick={(e) => scrollToSection(e, "#top")}
          className="flex items-center"
        >
          <img src={LOGO_SRC} alt="Simge logo" className="h-14 md:h-16 w-auto" />
        </a>

        <nav className="hidden md:flex items-center gap-9 font-body text-[15px]">
          {links.map((l) => (
            <a
              key={l.label}
              href={l.href}
              onClick={(e) => scrollToSection(e, l.href)}
              className="underline-grow"
              style={{ color: COLORS.ink }}
            >
              {l.label}
            </a>
          ))}
        </nav>

        <button
          aria-label="Toggle menu"
          className="md:hidden flex flex-col gap-1.5 w-7"
          onClick={() => setOpen((o) => !o)}
        >
          <motion.span
            animate={{ rotate: open ? 45 : 0, y: open ? 6 : 0 }}
            className="h-[2px] w-full rounded-full"
            style={{ backgroundColor: COLORS.ink }}
          />
          <motion.span
            animate={{ opacity: open ? 0 : 1 }}
            className="h-[2px] w-full rounded-full"
            style={{ backgroundColor: COLORS.ink }}
          />
          <motion.span
            animate={{ rotate: open ? -45 : 0, y: open ? -6 : 0 }}
            className="h-[2px] w-full rounded-full"
            style={{ backgroundColor: COLORS.ink }}
          />
        </button>
      </div>

      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="md:hidden overflow-hidden border-t"
            style={{ borderColor: `${COLORS.ink}1A` }}
          >
            <div className="flex flex-col px-6 py-4 gap-4 font-body text-[15px]">
              {links.map((l) => (
                <a
                  key={l.label}
                  href={l.href}
                  onClick={(e) => scrollToSection(e, l.href)}
                  style={{ color: COLORS.ink }}
                >
                  {l.label}
                </a>
              ))}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  );
}

