const SERVICES = [
  {
    title: "Typography Animation",
    desc: "Kinetic type systems that give words rhythm, weight, and meaning — built to carry a message on its own.",
    media: { type: "lottie", data: LOTTIE_KINETIC_TYPOGRAPHY },
  },
  {
    title: "Explainer Visuals",
    desc: "Complex products and ideas, distilled into clear sequences that make sense in seconds, not minutes.",
    media: { type: "lottie", data: LOTTIE_EXPLAINER },
  },
  {
    title: "Social Media Motion",
    desc: "Short-form animation tuned for the feed — built to stop the scroll without losing the brand voice.",
    media: { type: "lottie", data: LOTTIE_SOCIAL_MEDIA },
  },
  {
    title: "Concept-driven Animation",
    desc: "Original visual concepts developed from a single idea into a fully animated narrative.",
    media: { type: "lottie", data: LOTTIE_IDEA },
  },
];

function ServiceCard({ service, index }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 24 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-60px" }}
      transition={{ duration: 0.55, delay: index * 0.08, ease: "easeOut" }}
      whileHover={{ y: -4 }}
      className="rounded-3xl p-6 md:p-7 flex flex-row items-stretch gap-5 md:gap-6 h-full"
      style={{ backgroundColor: COLORS.accent }}
    >
      {/* Left — text area */}
      <div className="flex flex-col flex-1 min-w-0 justify-center">
        <h3
          className="font-display font-bold text-base md:text-lg leading-snug mb-2.5"
          style={{ color: COLORS.ink }}
        >
          {service.title}
        </h3>
        <p
          className="font-body text-[13px] md:text-[14px] leading-relaxed"
          style={{ color: "#000000" }}
        >
          {service.desc}
        </p>
      </div>

      {/* Right — graphic area. Falls back to a placeholder until `media` is set. */}
      <div
        className="shrink-0 w-[88px] sm:w-[104px] md:w-[120px] rounded-2xl flex items-center justify-center overflow-hidden"
        style={{ backgroundColor: "#FFFFFF" }}
        aria-hidden="true"
      >
        {service.media && service.media.type === "gif" ? (
          <img
            src={service.media.src}
            alt=""
            className="w-full h-full object-cover"
          />
        ) : service.media && service.media.type === "lottie" ? (
          <LottiePlayer animationData={service.media.data} />
        ) : (
          <span
            className="font-body text-[10px] tracking-widest uppercase text-center leading-tight px-2"
            style={{ color: `${COLORS.ink}55` }}
          >
            visual
          </span>
        )}
      </div>
    </motion.div>
  );
}

/* Minimal Lottie player — loads lottie-web from CDN on demand, no bundler
   dependency required. Pass the path to a Lottie JSON file as `src`. */
function LottiePlayer({ animationData }) {
  const containerRef = useRef(null);

  useEffect(() => {
    let anim;
    let cancelled = false;

    function init() {
      if (cancelled || !containerRef.current || !window.lottie) return;
      anim = window.lottie.loadAnimation({
        container: containerRef.current,
        renderer: "svg",
        loop: true,
        autoplay: true,
        animationData,
        rendererSettings: {
          preserveAspectRatio: "xMidYMid slice",
        },
      });
    }

    if (window.lottie) {
      init();
    } else {
      const script = document.createElement("script");
      script.src = "https://cdnjs.cloudflare.com/ajax/libs/lottie-web/5.12.2/lottie.min.js";
      script.onload = init;
      document.body.appendChild(script);
    }

    return () => {
      cancelled = true;
      if (anim) anim.destroy();
    };
  }, [animationData]);

  return (
    <div
      ref={containerRef}
      className="w-full h-full"
      style={{ transform: "scale(1.04)", backgroundColor: "#FFFFFF" }}
    />
  );
}

/* Scrolling software marquee — duplicated list for seamless loop */
const TOOLS = [
  "Adobe Illustrator",
  "Adobe Photoshop",
  "After Effects",
  "Premiere Pro",
  "Blender",
];

function ToolBadge({ name }) {
  return (
    <span
      className="font-body font-bold text-sm md:text-base px-6 py-3 rounded-full whitespace-nowrap shrink-0"
      style={{
        backgroundColor: COLORS.ink,
        color: "#FFFFFF",
      }}
    >
      {name}
    </span>
  );
}

function ToolsMarquee() {
  const loopList = [...TOOLS, ...TOOLS, ...TOOLS];
  return (
    <div className="tools-marquee-gap overflow-hidden">
      <p
        className="font-display font-bold text-lg md:text-xl text-center mb-6"
        style={{ color: COLORS.ink }}
      >
        Tools I work with
      </p>
      <div className="relative w-full overflow-hidden">
        <div className="flex gap-3 marquee-track w-max">
          {loopList.map((tool, i) => (
            <ToolBadge key={`${tool}-${i}`} name={tool} />
          ))}
        </div>
      </div>
    </div>
  );
}

function Services() {
  return (
    <section id="services" className="px-6 pt-28 md:pt-40 pb-20 md:pb-28">
      <div className="max-w-5xl mx-auto">
        <motion.h2
          initial={{ opacity: 0, y: 16 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
          className="font-display font-bold text-3xl md:text-4xl text-center mb-20 md:mb-24"
          style={{ color: COLORS.ink }}
        >
          What{" "}
          <span className="relative inline-block">
            I do best
            <span className="absolute left-0 top-full w-full flex justify-center" style={{ marginTop: "2px" }}>
              <UnderlineDoodle />
            </span>
          </span>
        </motion.h2>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-5 md:gap-6">
          {SERVICES.map((s, i) => (
            <ServiceCard key={s.title} service={s} index={i} />
          ))}
        </div>

        <ToolsMarquee />
      </div>
    </section>
  );
}

