/* ---------------------------------------------
   CONTACT FORM
--------------------------------------------- */
function ContactForm() {
  const [form, setForm] = useState({ name: "", email: "", message: "" });
  const [sent, setSent] = useState(false);
  const CONTACT_EMAIL = "sembolstudio@gmail.com";

  function handleSubmit(e) {
    e.preventDefault();
    const subject = encodeURIComponent(`Project inquiry from ${form.name}`);
    const body = encodeURIComponent(
      `Name: ${form.name}\nEmail: ${form.email}\n\n${form.message}`
    );
    window.location.href = `mailto:${CONTACT_EMAIL}?subject=${subject}&body=${body}`;
    setSent(true);
    setTimeout(() => setSent(false), 3500);
    setForm({ name: "", email: "", message: "" });
  }

  const inputStyle = {
    backgroundColor: "#FFFFFF",
    border: `1px solid ${COLORS.ink}26`,
    color: COLORS.ink,
  };

  return (
    <section id="contact" className="px-6 py-28 md:py-40">
      <div className="max-w-xl mx-auto">
        <motion.h2
          initial={{ opacity: 0, y: 16 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
          className="font-display font-bold text-3xl md:text-4xl text-center mb-12 md:mb-14"
          style={{ color: COLORS.ink }}
        >
          Let's{" "}
          <span className="relative inline-block">
            talk
            <span className="absolute left-0 top-full w-full flex justify-center" style={{ marginTop: "2px" }}>
              <UnderlineDoodle />
            </span>
          </span>
        </motion.h2>
        <motion.p
          initial={{ opacity: 0, y: 16 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6, delay: 0.1 }}
          className="font-body text-center text-sm md:text-base mb-12"
          style={{ color: `${COLORS.ink}99` }}
        >
          Tell me about your project — I usually reply within a day.
        </motion.p>

        <motion.form
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6, delay: 0.15 }}
          onSubmit={handleSubmit}
          className="flex flex-col gap-4"
        >
          <input
            required
            type="text"
            placeholder="Name"
            value={form.name}
            onChange={(e) => setForm({ ...form, name: e.target.value })}
            className="font-body text-sm rounded-xl px-4 py-3.5 outline-none transition-shadow focus:ring-2"
            style={{ ...inputStyle, "--tw-ring-color": COLORS.accent2 }}
          />
          <input
            required
            type="email"
            placeholder="Email"
            value={form.email}
            onChange={(e) => setForm({ ...form, email: e.target.value })}
            className="font-body text-sm rounded-xl px-4 py-3.5 outline-none transition-shadow focus:ring-2"
            style={{ ...inputStyle, "--tw-ring-color": COLORS.accent2 }}
          />
          <textarea
            required
            rows={5}
            placeholder="Message"
            value={form.message}
            onChange={(e) => setForm({ ...form, message: e.target.value })}
            className="font-body text-sm rounded-xl px-4 py-3.5 outline-none resize-none transition-shadow focus:ring-2"
            style={{ ...inputStyle, "--tw-ring-color": COLORS.accent2 }}
          />

          <motion.button
            type="submit"
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            className="font-body font-bold text-sm rounded-full px-8 py-3.5 mt-2 self-center"
            style={{ backgroundColor: COLORS.ink, color: COLORS.bg }}
          >
            {sent ? "Message sent ✓" : "Send message"}
          </motion.button>
        </motion.form>
      </div>
    </section>
  );
}

